class Solution:
    def numIslands(self, grid):
        if not grid:
            return 0
        rows, cols = len(grid), len(grid[0])
        # Work on a copy so we don't mutate the original
        g = [row[:] for row in grid]
        count = 0
        for r in range(rows):
            for c in range(cols):
                if g[r][c] == '1':
                    count += 1
                    # BFS flood-fill
                    queue = [(r, c)]
                    g[r][c] = '0'
                    while queue:
                        cr, cc = queue.pop(0)
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                            nr, nc = cr+dr, cc+dc
                            if 0 <= nr < rows and 0 <= nc < cols and g[nr][nc] == '1':
                                g[nr][nc] = '0'
                                queue.append((nr, nc))
        return count

